WITH src AS (SELECT datname AS database_name, pid AS process_id, usename AS user_name, application_name, client_addr AS client_address, client_port, backend_start, xact_start, query_start, state_change, wait_event_type, wait_event, state, query AS active_query, backend_type FROM pg_stat_activity WHERE NOT state IS NULL) SELECT CHR(34) || :PKEY || CHR(34) AS pkey, CHR(34) || :DMA_SOURCE_ID || CHR(34) AS dma_source_id, CHR(34) || :DMA_MANUAL_ID || CHR(34) AS dma_manual_id, src.database_name, src.process_id, src.user_name, CHR(34) || application_name || CHR(34) AS application_name, src.client_address, src.client_port, src.backend_start, src.xact_start, src.query_start, src.state_change, src.wait_event_type, src.wait_event, src.state, src.active_query, src.backend_type FROM src